const listJournals = `-- name: ListJournals :many
  SELECT
      j.id,
      j.title,
      j.course_symbol,
      j.organizer_name,
      j.location,
      j.form_of_training,
      j.date_start,
      j.date_end,
      j.total_hours,
      j.status,
      j.created_at,
      c.id AS course_id,
      c.name AS course_name,
      comp.id AS company_id,
      comp.name AS company_name,
      (
          SELECT COUNT(*)::bigint
          FROM training_journal_attendees a
          WHERE a.journal_id = j.id
      ) AS attendees_count,
      (
          SELECT COUNT(*)::bigint
          FROM training_journal_sessions s
          WHERE s.journal_id = j.id
      ) AS sessions_count
  FROM training_journals j
  JOIN courses c ON c.id = j.course_id
  LEFT JOIN companies comp ON comp.id = j.company_id
  WHERE
      (
          $1::text IS NULL
          OR COALESCE(j.title, '') ILIKE '%' || $1::text || '%'
          OR COALESCE(j.course_symbol, '') ILIKE '%' || $1::text || '%'
          OR COALESCE(c.name, '') ILIKE '%' || $1::text || '%'
          OR COALESCE(comp.name, '') ILIKE '%' || $1::text || '%'
          OR COALESCE(j.location, '') ILIKE '%' || $1::text || '%'
          OR COALESCE(j.organizer_name, '') ILIKE '%' || $1::text || '%'
      )
      AND (
          $2::bigint IS NULL
          OR j.course_id = $2::bigint
      )
      AND (
          $3::bigint IS NULL
          OR j.company_id = $3::bigint
      )
      AND (
          $4::text IS NULL
          OR j.status = $4::text
      )
      AND (
          $5::date IS NULL
          OR j.date_start >= $5::date
      )
      AND (
          $6::date IS NULL
          OR j.date_end <= $6::date
      )
  ORDER BY j.date_start DESC, j.id DESC
  LIMIT $7
`

