const upsertJournalAttendance = `-- name: UpsertJournalAttendance :one
  WITH valid_pair AS (
      SELECT
          s.id AS journal_session_id,
          a.id AS journal_attendee_id
      FROM training_journal_sessions s
      JOIN training_journal_attendees a ON a.journal_id = s.journal_id
      WHERE s.journal_id = $2
        AND s.id = $3
        AND a.id = $4
  )
  INSERT INTO training_journal_attendance (
      journal_session_id,
      journal_attendee_id,
      present
  )
  SELECT
      vp.journal_session_id,
      vp.journal_attendee_id,
      $1
  FROM valid_pair vp
  ON CONFLICT (journal_session_id, journal_attendee_id)
  DO UPDATE SET
      present = EXCLUDED.present,
      updated_at = now()
  RETURNING
      id,
      journal_session_id,
      journal_attendee_id,
      present,
      created_at,
      updated_at
`

type UpsertJournalAttendanceParams struct {
	Present           bool  `json:"present"`
	JournalID         int64 `json:"journal_id"`
	JournalSessionID  int64 `json:"journal_session_id"`
	JournalAttendeeID int64 `json:"journal_attendee_id"`
}

func (q *Queries) UpsertJournalAttendance(ctx context.Context, arg UpsertJournalAttendanceParams) (TrainingJournalAttendance, error) {
	row := q.db.QueryRow(ctx, upsertJournalAttendance,
		arg.Present,
		arg.JournalID,
		arg.JournalSessionID,
		arg.JournalAttendeeID,
	)
	var i TrainingJournalAttendance
	err := row.Scan(
		&i.ID,
		&i.JournalSessionID,
		&i.JournalAttendeeID,
		&i.Present,
		&i.CreatedAt,
		&i.UpdatedAt,
	)
	return i, err
}

